local TableContains = function(t, value) for k, v in pairs(t) do if v == value then return true end end return false end local Clamp = function(num, min, max) return math.min(math.max(num, min), max) end local LootSystem = {} LootSystem.weaponLootTable = {lv1 = { "axe" , "pickaxe" , "hammer" , "pitchfork" , "shovel" , "torch" , "machete" , "spear" , "needlespear" }, lv2 = { "spear_poison" , "peg_leg" , "brush" , "bugnet" , "fishingrod" , "goldenaxe" , "goldenpickaxe" , "goldenshovel" }, lv3 = { "cork_bat" , "halberd" , "batbat" , "multitool_axe_pickaxe" , "tentaclespike" , "hambat" , "icestaff" , "firestaff" , "obsidianaxe" , "obsidianmachete" }, lv4 = { "spear_obsidian" , "nightstick" , "cutlass" , "nightsword" , "ruins_bat" , "trident" , "cane" },} LootSystem.armorLootTable = {lv1 = { "armorgrass" , "armorwood" , "beehat" ,}, lv2 = { "armorseashell" , "antsuit" , "armor_weevole" , "footballhat" , "oxhat" , "antmaskhat" ,}, lv3 = { "armor_sanity" , "armorcactus" , "armormarble" , "armorlimestone" , "armor_metalplate" , "slurtlehat" , "metalplatehat" , "armor_bramble" ,}, lv4 = { "armorruins" , "armorsnurtleshell" , "armordragonfly" , "armorobsidian" , "ruinshat" , "slurtlehat" ,},} LootSystem.weaponEncTable = {lv1 = { "damage_5" , "damage_10" , "damage_15" , "damage_20" , "damage_5p" , "damage_10p" , "damage_15p" , "damage_20p" , "healthdrain_1c40" , "healthdrain_10c5" , "sanitydrain_1c25" , "sanitydrain_6c5" , "speed_0_5" , "speed_1" , "attackspeed_10p" , "poisoner_c10" , "poisoner_c20" , "criticalstrike_200c10" , "criticalstrike_200c20" , "recycle_1" , "cripple_c15" ,}, lv2 = { "sanitydrain_3c20" , "healthdrain_5c20" , "lifesteal_5" , "lifesteal_10" , "lifesteal_15" , "lifesteal_20" , "igniter_c20" , "igniter_c25" , "igniter_c30" , "speed_1" , "speed_1_5" , "attackspeed_20p" , "nightdamage_40" , "criticalstrike_300c8" , "criticalstrike_200c30" , "beekiller" , "insectkiller" , "snakekiller" , "recycle_2" , "cripple_c30" , "strategist" , "hitandrun" ,}, lv3 = { "freezer_c20" , "freezer_c25" , "freezer_c30" , "speed_1_5" , "speed_2" , "attackspeed_30p" , "nightdamage_55" , "noslippyhand" , "disarm" , "spiderkiller" , "pigkiller" , "nightmarekiller" , "ghostkiller" , "houndkiller" , "insanedamage" , "woundeddamage" , "hungrydamage" , "criticalstrike_300c15" , "criticalstrike_500c8" , "recycle_3" , "strategist" , "hitandrun" ,}, lv4 = { "bladeofwind" , "laserbeam" , "meteor" , "speed_2_5" , "attackspeed_50p" , "nightdamage_70" , "giantkiller" , "criticalstrike_500c15" , "recycle_4" , "fury" , "weaken" ,},} LootSystem.armorEncTable = {lv1 = { "damagereduction_5" , "damagereduction_5p" , "rebounddamage_5" , "rebounddamage_10" , "rebounddamage_5p" , "maxhealth_25" , "maxhealth_50" , "maxhealth_5p" , "speed_0_5" , "icebody_c10" , "firebody_c10" , "poisonbody_25" , "recycle_1" , "vision_1" , "fireresistance_20p" , "quickunfreeze_30p" , "fistdamage_30" , "followerdamage_20" ,}, lv2 = { "damagereduction_10" , "damagereduction_10p" , "rebounddamage_10" , "rebounddamage_15" , "rebounddamage_10p" , "maxhealth_50" , "maxhealth_75" , "maxhealth_10p" , "speed_1" , "icebody_c20" , "firebody_c20" , "poisonbody_50" , "recycle_2" , "vision_2" , "fireresistance_20p" , "quickunfreeze_30p" , "fistdamage_60" , "followerdamage_40" ,}, lv3 = { "damagereduction_15" , "damagereduction_15p" , "rebounddamage_15" , "rebounddamage_20" , "rebounddamage_15p" , "maxhealth_75" , "maxhealth_100" , "maxhealth_15p" , "speed_1_5" , "speed_2" , "icebody_c30" , "firebody_c30" , "recycle_3" , "vision_3" , "poisonimmunity" , "fireresistance_40p" , "fistdamage_90" , "followerdamage_100p" , "followerdamagereduction_50p" ,}, lv4 = { "rebounddamage_30" , "rebounddamage_20p" , "maxhealth_125" , "maxhealth_20p" , "shadowshield" , "speed_2_5" , "recycle_4" , "vision_4" , "poisonimmunity" , "quickunfreeze_60p" ,},} LootSystem.rareEncTable = { "recycle_quick" , "maxhealth_200" , "laserbeam_late" , "bladeofwind_late" , "damagereduction_30" , "sacreddefense" , "phantomassault" ,} LootSystem.bossTable = { "dragonfly" , "deerclops" , "bearger" , "moose" , "twister" , "tigershark" , "kraken" , "pugalisk" , "antqueen" , "ancient_herald" , "ancient_hulk" , "minotaur" , "beequeen" , "toadstool" , "klaus" , "antlion" , "malbatross" , "crabking" ,} LootSystem.weakBossTable = { "leif_sparse" , "leif" , "treeguard" , "spiderqueen" , "worm" , "warg" ,} function LootSystem:Init(data) self.randomLootDrop = data.randomLootDrop self.lootDropMultiplier = data.lootDropMultiplier or 0x1 GetWorld():ListenForEvent( "entity_death" , function(world, data) self:OnAnyoneDie(data.inst, data.cause) end) end local function GetChance(hpmax, dmg, encCount) hpmax = hpmax or 0x0 dmg = dmg or 0x0 encCount = encCount or 0x0 local chance = 0.0001 if dmg > 0x0 then if hpmax and hpmax >= 0x2710 then chance = 0.80 + (dmg >= 0x64 and 0.12 or dmg >= 0x32 and 0.06 or 0x0) elseif hpmax and hpmax >= 0x1388 then chance = 0.60 + (dmg >= 0x64 and 0.12 or dmg >= 0x32 and 0.06 or 0x0) elseif hpmax and hpmax >= 0x7d0 then chance = 0.40 + (dmg >= 0x64 and 0.12 or dmg >= 0x32 and 0.06 or 0x0) elseif hpmax and hpmax >= 0x3e8 then chance = 0.18 + (dmg >= 0x64 and 0.12 or dmg >= 0x32 and 0.06 or 0x0) elseif hpmax and hpmax >= 0x1f4 then chance = 0.068 + (dmg >= 0x64 and 0.12 or dmg >= 0x32 and 0.06 or 0x0) elseif hpmax and hpmax >= 0x12c then chance = 0.038 + (dmg >= 0x64 and 0.08 or dmg >= 0x32 and 0.04 or 0x0) elseif hpmax and hpmax >= 0x64 then chance = 0.009 + (dmg >= 0x64 and 0.04 or dmg >= 0x32 and 0.02 or 0x0) end end chance = chance + encCount / 0x32 return chance end local function GetLegendaryGemChance(inst) local chance = 0.19 local encCount = inst:GetEnchantmentCount() chance = chance + encCount / 0x1e return chance end function LootSystem:IsStrongBoss(other) return self.bossTable and other and other.prefab and TableContains(self.bossTable, other.prefab) end function LootSystem:IsWeakBoss(other) return self.weakBossTable and other and other.prefab and TableContains(self.weakBossTable, other.prefab) end function LootSystem:IsBoss(other) return self.bossTable and self.weakBossTable and other and other.prefab and (TableContains(self.bossTable, other.prefab) or TableContains(self.weakBossTable, other.prefab)) end function LootSystem:GetLootPrefab(lv) lv = lv or "lv1" local rand = math.random() local tbl = rand < 0.4 and self.armorLootTable or self.weaponLootTable local list = tbl[lv] or tbl.lv1 return list[math.random(0x1, #list)] end function LootSystem:GetEnchantment(inst, rand) rand = rand or math.random() local lv = rand > 0.94 and "lv4" or rand > 0.8 and "lv3" or rand > 0.5 and "lv2" or "lv1" local armor = inst and inst.components.armor local tbl = armor and self.armorEncTable or self.weaponEncTable local list = tbl[lv] or tbl.lv1 return list[math.random(0x1, #list)] end function LootSystem:GetEnchantmentByLevel(inst, lv) lv = Clamp(lv, 0x1, 0x4) lv = "lv"..lv local armor = inst and inst.components.armor local tbl = armor and self.armorEncTable or self.weaponEncTable local list = tbl[lv] or tbl.lv1 return list[math.random(0x1, #list)] end function LootSystem:NewEncStone(names, pos) local inst = SpawnPrefab( "dyc_gem_enc2" ) if pos then inst.Transform:SetPosition(pos.x, pos.y, pos.z) end if inst and inst.components.inventoryitem then local enchanter = inst.components.inventoryitem:GetEnchanter() if enchanter then enchanter.enchantments = {} if names then for k, v in pairs(names) do table.insert(enchanter.enchantments, {names = {v},}) end end end end return inst end local function AddEnchantmentAndSetQuality(self, loot, encCount) if not loot then return end encCount = encCount or 0x0 if loot.AddEnchantment then local rand = math.random() / (encCount > 0x0 and encCount / 0x2 + 0x1 or 0x1) local encNum = rand < 0.003 and 0x4 or rand < 0.02 and 0x3 or rand < 0.15 and 0x2 or 0x1 local try = 0x0 local i = 0x0 while i < encNum and try < 0x64 do local encName = self:GetEnchantment(loot, math.random()) local enc = loot:AddEnchantment(encName, true) if enc then i = i + 0x1 end try = try + 0x1 end end if loot.SetRandomQuality then loot:SetRandomQuality() end end function LootSystem:OnAnyoneDie(inst, cause) local pos = inst and inst:GetPosition() local days = (GetClock().numcycles or 0x0) + 0x1 if self.randomLootDrop and inst and not inst.dycLootDropped then inst.dycLootDropped = true local encCount = inst:GetEnchantmentCount() local health = inst.components.health local combat = inst.components.combat local hpmax = health and (health.GetMax and health:GetMax() or health.maxhealth) or 0x0 local dmg = combat and combat.defaultdamage local chance = GetChance(hpmax, dmg, encCount) * self.lootDropMultiplier if math.random() <= chance * 1.4 then local loot = nil local count = 0x0 while loot == nil and count < 0x32 do loot = self:SpawnLoot(self:GetLootPrefab( "lv1" ), pos, inst) count = count + 0x1 end AddEnchantmentAndSetQuality(self, loot, encCount) end if math.random() <= chance then local loot = nil local count = 0x0 while loot == nil and count < 0x32 do loot = self:SpawnLoot(self:GetLootPrefab( "lv2" ), pos, inst) count = count + 0x1 end AddEnchantmentAndSetQuality(self, loot, encCount) end if math.random() <= chance * 0.5 then local loot = nil local count = 0x0 while loot == nil and count < 0x32 do loot = self:SpawnLoot(self:GetLootPrefab( "lv3" ), pos, inst) count = count + 0x1 end AddEnchantmentAndSetQuality(self, loot, encCount) end if math.random() <= chance * 0.13 then local loot = nil local count = 0x0 while loot == nil and count < 0x32 do loot = self:SpawnLoot(self:GetLootPrefab( "lv4" ), pos, inst) count = count + 0x1 end AddEnchantmentAndSetQuality(self, loot, encCount) end end if inst and math.random() <= GetLegendaryGemChance(inst) and self:IsStrongBoss(inst) and not inst.dycLegendaryGemDropped then inst.dycLegendaryGemDropped = true local uniqueGems = { "dyc_gem_blue" , "dyc_gem_purple" , "dyc_gem_orange" ,} local rand = math.random() local index = math.random(0x1, #uniqueGems) local count = 0x0 local gem = nil while gem == nil and count <= #uniqueGems do local gemPrefab = uniqueGems[index] local hasGem = false for k, v in pairs(Ents) do if v and (v.prefab and v.prefab == gemPrefab or v:HasTag(gemPrefab)) then hasGem = true break end end if not hasGem then gem = self:SpawnLoot(gemPrefab, pos, inst) end if not gem then index = index + 0x1 index = index > #uniqueGems and 0x1 or index end count = count + 0x1 end end if math.random() <= 0.75 and inst and self:IsBoss(inst) and not inst.dycEncGemDropped then inst.dycEncGemDropped = true local encPf = days >= 0x78 and math.random() < 0.5 and "dyc_gem_enc5" or (days >= 0x50 and math.random() < 0.3 and "dyc_gem_enc5" ) or (days >= 0x28 and math.random() < 0.1 and "dyc_gem_enc5" ) or "dyc_gem_enc" self:SpawnLoot(math.random() <= 0.13 and "dyc_gem_enc4" or encPf, pos, inst) end local goldEncRand = math.random() if(goldEncRand <= 0.001 and days >= 0x3c or goldEncRand <= 0.008 and days >= 0x78 or goldEncRand <= 0.016 and days >= 0xb4) and inst and self:IsBoss(inst) and not inst.dycGoldEncGemDropped then inst.dycGoldEncGemDropped = true local tbl = self.rareEncTable self:SpawnLoot(self:NewEncStone({tbl[math.random(#tbl)]}), pos, inst) end end function LootSystem:SpawnLoot(pf, pt, dropper) if pf then local loot = type(pf) == "string" and SpawnPrefab(pf) or type(pf) == "table" and pf if loot and type(loot) == "table" and loot.Transform then loot.Transform:SetPosition(pt.x, pt.y, pt.z) if dropper and dropper.ApplyInheritedMoisture then dropper:ApplyInheritedMoisture(loot) end if loot.Physics then local angle = math.random() * 0x2 * PI local speed = 0x3 loot.Physics:SetVel(speed * math.cos(angle), 0xf, speed * math.sin(angle)) if loot and loot.Physics and dropper and dropper.Physics then pt = pt + Vector3(math.cos(angle), 0x0, math.sin(angle)) * ((loot.Physics:GetRadius() or 0x1) + (dropper.Physics:GetRadius() or 0x1)) loot.Transform:SetPosition(pt.x, pt.y, pt.z) end loot:DoTaskInTime(0x1, function() if not(loot.components.inventoryitem and loot.components.inventoryitem:IsHeld()) then if not loot:IsOnValidGround() then local fx = SpawnPrefab( "splash_ocean" ) local pos = loot:GetPosition() fx.Transform:SetPosition(pos.x, pos.y, pos.z) if loot:HasTag( "irreplaceable" ) then loot.Transform:SetPosition(GetPlayer().Transform:GetWorldPosition()) else loot:Remove() end end end end) end return loot end end end return LootSystem 